// src/main.ts
var program2 = new Command();
async function main() {
  program2.name("cyrene-continuity").description("Cyrene continuity MCP and Codex bridge.").argument("[command...]").option("--cwd <path>", "working directory", process.cwd()).allowUnknownOption();
  program2.parse();
  const options = program2.opts();
  const command = program2.args[0];
  if (command === "codex") {
    await handleCodexCommand({
      cwd: options.cwd,
      args: program2.args.slice(1),
      runtimeEntryPath: fileURLToPath3(import.meta.url)
    });
    return;
  }
  if (command === "mcp-server") {
    if (program2.args.length > 2 || program2.args[1] !== void 0 && program2.args[1] !== "--stdio") {
      console.error("Usage: cyrene-continuity mcp-server --stdio");
      process.exit(1);
    }
    await startCyreneMcpServer({ cwd: options.cwd, transport: "stdio" });
    return;
  }
  console.error("Usage: cyrene-continuity <mcp-server --stdio|codex ...>");
  process.exit(1);
}
main().catch((error2) => {
  console.error(error2 instanceof Error ? error2.message : String(error2));
  process.exit(1);
});
